const FamilyDashboardView  = ({ tabs, active, updTab }) => {
	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}

	const updKey =  (v,f) => {
		let d2u = {[f]:v};	
		save(d2u)
	}

	
	const save =  async(v) => {
		
		let cId = getStore(qryKClient())?.["clientNotaryId"];
		let bdyq2 = {...getStore(qryStore())?.upd_notary};
		bdyq2.params = {
			"clientNotaryId": cId
		}
		bdyq2.data2update = v;	

		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			getById_notary(cId,updObs);
		}

	}

	const addKids =  (v) => {
		let childrens = getStore(qryKClient())?.childrens || {};
		if(Array.isArray(getStore(qryKClient())?.childrens)){
			childrens ={};
		}
		childrens[v] = 1;
		let d2u = {childrens};
		save(d2u);
	}

	const rmvKid =  (v) => {
		let childrens = getStore(qryKClient())?.childrens || {};
		delete childrens[v];
		let d2u = {childrens};
		save(d2u);
		window.scrollTo(0,0);
	}
	
	const addSibling =  (v) => {
		let siblings = getStore(qryKClient())?.siblings || {};
		if(Array.isArray(getStore(qryKClient())?.siblings)){
			siblings ={};
		}
		siblings[v] = 1;
		let d2u = {siblings};
		save(d2u);
	}

	const rmvSibling =  (v) => {
		let siblings = getStore(qryKClient())?.siblings || {};
		delete siblings[v];
		let d2u = {siblings};
		save(d2u);
		window.scrollTo(0,0);
	}

	

	let clientItm = getStore(qryKClient());

	



	return (
		<div>
			<div style={{paddingTop: 30}}/>

			<div className="_dsplFlx " >
				<div className="iMTYiw" style={{marginTop: "8px"}}>
					Familia 
				</div>
			</div>

			<div className="_dsplFlx " >
				<div className="flexSpace"/>
				<AddChild
					title={"Add Child"}
					updKey={addKids}
				/>

				<div className="flexSpace"/>
				<AddChild
					title={"Add Sibling"}
					updKey={addSibling}
				/>
				<div className="flexSpace"/>
			</div>

			<div style={{paddingTop: 30}}/>
			
				<ItemDashboardView 
					title={"Father"}
					item={clientItm?.fatherInfo}
					updKey={updKey}
					fld={"father"}
				/>

				<ItemDashboardView 
					title={"Mother"}
					item={clientItm?.motherInfo}
					updKey={updKey}
					fld={"mother"}
				/>

				<ItemSpouseView 
					title={"Spouse"}
					item={clientItm}
					fld={"spouse"}
					updKey={updKey}
					notMandatory={true}
				/>

			{clientItm?.childrensInfo?.length>0?
			<div className="lbl_h_dtls"  style={{textAlign: "left", padding: 16}}>
								Childrens: 
			</div>
			:null}
			{clientItm?.childrensInfo?.map(chl=>{
				return (
					<ItemChildView 
						key={"kid" + chl.clientNotaryId}
						item={chl}
						fld={"kid"}
						updKey={rmvKid}
					/>
				)
			})}
			


			{clientItm?.siblingsInfo?.length>0?
			<div className="lbl_h_dtls"  style={{textAlign: "left", padding: 16}}>
				Siblings: 
			</div>
			:null}
			{clientItm?.siblingsInfo?.map(chl=>{
				return (
					<ItemChildView 
						key={"sibling" + chl.clientNotaryId}
						item={chl}
						fld={"sibling"}
						updKey={rmvSibling}
					/>
				)
			})}
				




		</div>
          
	)
}


const AddChild  = ({updKey, title }) => {

	const [show, setShow] = useState(false);

	const select  =  (e)  => {
		updKey(e.id);
		setShow(false);
	};

	return (
		<div className="_dsplFlx " >
			<div className="flexSpace"/>
			{show ?
			<div className="client_item_box gWXAaj jlytmu">
				<div className="_dsplFlx " >
				
					<div className="_dsplFlx dtls header_card">
						<div className="lbl_h_dtls">
							{title} 
						</div>
						
					</div>
					<div className="flexSpace"/>
					<PickPerson
						onSelect={select}
					/>
				</div>	
			</div>	
			:		
			<div className="iSTOvb kvXcCL"  style={{padding: "0 9px" , width: "160px"}}  onClick={()=>setShow(!show)}>
				{title}
			</div>
			}
		</div>

	)

}









export default FamilyDashboardView;













const ItemDashboardView  = ({ item, title, updKey, fld, notMandatory }) => {


	const [hasCondition, setHasCondition] = useState(false);
	
	const copyToClpb  =  (v)  => {

		copyToClipboard(v);
	};

	useEffect(() => {
		if(item){
			setHasCondition(true)
		}
    },[item]);


	let showPick =  notMandatory ? hasCondition : true ;


	const rmv  =  (v)  => {

		let lastTimeCallModal = getStore("lastTimeCallModal") || 0;
		if(Date.now() > lastTimeCallModal){
			updStore("lastTimeCallModal", Date.now()+320);
			
			let modaldata = {};
			modaldata["zIndex"] = 450;
			modaldata["height"] = "40vh";
			// data['observeResize']=true;
			modaldata["props"] = { minHeight: "1vh", overlay: true, closeEvent: ()=>{}  };
			modaldata["content"] = <DeleteAlert
				confirm={()=>updKey(null,fld)}
				lbl_p={"Eliminar"} 
				lbl_span={"Se eliminara la referencia puede asociarlo nuevamente cuando quiera"}
			/>
			OpenModal(modaldata);
		}
	}
	

	return (


		
	<div className="client_item_box gWXAaj jlytmu" style={{marginBottom: 14}}>
		<div className="_dsplFlx ">

			<div className="i0nYPrn" style={{textAlign: "left"}}>
				{title} 
			</div>
			{notMandatory?
			<div className="_dsplFlx " style={{marginTop: 4}}>
				<CheckBoxSlide
					initvalue={hasCondition}
					keyCode={37}
					updChange={setHasCondition}
					color={"var(--primary)"}
				/>
				<span className={`checklabel`}>
					{"Tiene Esposa"}
				</span>
			</div>
			:null}
			<div className="flexSpace"/>
			<div onClick={rmv}>
				<Svg 
					name={"outline_delete"} 
					color={"var(--light-300)"}
				/>
			</div>
			
		</div>
		
	
		
		{showPick && (
		<div className="_dsplFlx " >
			
			<div className="_dsplFlx dtls header_card">
				<div className="lbl_h_dtls">
					Full Name: 
				</div>
				<div className="lbl_dtls" onClick={()=>copyToClpb(txtOrempty(item?.firstName) + txtOrempty(item?.middleName)  + txtOrempty(item?.lastName))}>
					{txtOrempty(item?.firstName) + txtOrempty(item?.middleName)  + txtOrempty(item?.lastName)}
				</div>
			</div>
			<div className="flexSpace"/>
			<PickPerson 
				init={txtOrempty(item?.firstName) + txtOrempty(item?.middleName)  + txtOrempty(item?.lastName)} 
				emptyLabel={title} 
				onSelect={(e)=>updKey(e.id,fld)}
			/>
		</div>	
		)}
		<ItemInfoView item={item}/>
	</div>

	)
}










